import { afterEach, beforeEach, describe, expect, it, vi } from "vitest";
vi.mock("node:child_process", () => ({
    execFileSync: vi.fn(),
    spawn: vi.fn(() => ({ on: vi.fn() })),
}));
import { execFileSync, spawn } from "node:child_process";
import { recordFocus } from "./frontmostApp.js";
const mockedExecFileSync = vi.mocked(execFileSync);
const mockedSpawn = vi.mocked(spawn);
describe("recordFocus", () => {
    const originalPlatform = process.platform;
    beforeEach(() => {
        vi.clearAllMocks();
    });
    afterEach(() => {
        Object.defineProperty(process, "platform", { value: originalPlatform });
    });
    describe("macOS", () => {
        beforeEach(() => {
            Object.defineProperty(process, "platform", { value: "darwin" });
        });
        it("captures frontmost app via osascript", () => {
            mockedExecFileSync.mockReturnValue("Terminal\n");
            recordFocus();
            expect(mockedExecFileSync).toHaveBeenCalledWith("osascript", [
                "-e",
                'tell application "System Events" to get name of first process whose frontmost is true',
            ], expect.objectContaining({ stdio: "pipe", encoding: "utf-8" }));
        });
        it("restores focus via osascript activate", () => {
            mockedExecFileSync.mockReturnValue("Terminal\n");
            const restore = recordFocus();
            restore();
            expect(mockedSpawn).toHaveBeenCalledWith("osascript", ["-e", 'tell application "Terminal" to activate'], expect.objectContaining({ stdio: "ignore" }));
        });
        it("no-ops restore when capture fails", () => {
            mockedExecFileSync.mockImplementation(() => {
                throw new Error("not found");
            });
            const restore = recordFocus();
            restore();
            expect(mockedSpawn).not.toHaveBeenCalled();
        });
    });
    describe("Linux", () => {
        beforeEach(() => {
            Object.defineProperty(process, "platform", { value: "linux" });
        });
        it("captures active window via xdotool", () => {
            mockedExecFileSync.mockReturnValue("12345678\n");
            recordFocus();
            expect(mockedExecFileSync).toHaveBeenCalledWith("xdotool", ["getactivewindow"], expect.objectContaining({ stdio: "pipe", encoding: "utf-8" }));
        });
        it("restores focus via xdotool windowactivate", () => {
            mockedExecFileSync.mockReturnValue("12345678\n");
            const restore = recordFocus();
            restore();
            expect(mockedSpawn).toHaveBeenCalledWith("xdotool", ["windowactivate", "12345678"], expect.objectContaining({ stdio: "ignore" }));
        });
    });
    describe("Windows", () => {
        beforeEach(() => {
            Object.defineProperty(process, "platform", { value: "win32" });
        });
        it("captures foreground window via PowerShell GetForegroundWindow", () => {
            mockedExecFileSync.mockReturnValue("131586\n");
            recordFocus();
            expect(mockedExecFileSync).toHaveBeenCalledWith("powershell.exe", [
                "-NoProfile",
                "-Command",
                expect.stringContaining("GetForegroundWindow"),
            ], expect.objectContaining({
                stdio: "pipe",
                encoding: "utf-8",
                timeout: 5000,
            }));
        });
        it("constructs valid DllImport with correct quoting in capture command", () => {
            mockedExecFileSync.mockReturnValue("131586\n");
            recordFocus();
            const args = mockedExecFileSync.mock.calls[0][1];
            const command = args[2];
            expect(command).toContain('[DllImport("user32.dll")]');
            expect(command).toContain("-Name WinFocus -Namespace Bitfab");
            expect(command).toContain("[Bitfab.WinFocus]::GetForegroundWindow().ToInt64()");
        });
        it("restores focus with Alt key trick before SetForegroundWindow", () => {
            mockedExecFileSync.mockReturnValue("131586\n");
            const restore = recordFocus();
            restore();
            const args = mockedSpawn.mock.calls[0][1];
            const script = args[2];
            expect(script).toContain('[DllImport("user32.dll")]');
            expect(script).toContain("keybd_event(0x12, 0, 1,");
            expect(script).toContain("SetForegroundWindow([IntPtr]::new(131586))");
            expect(script).toContain("keybd_event(0x12, 0, 3,");
        });
        it("rejects non-numeric HWND to prevent command injection", () => {
            mockedExecFileSync.mockReturnValue("not-a-number\n");
            const restore = recordFocus();
            restore();
            expect(mockedSpawn).not.toHaveBeenCalled();
        });
        it("accepts large HWND values", () => {
            mockedExecFileSync.mockReturnValue("140737488355328\n");
            const restore = recordFocus();
            restore();
            const args = mockedSpawn.mock.calls[0][1];
            expect(args[2]).toContain("[IntPtr]::new(140737488355328)");
        });
    });
    describe("unsupported platforms", () => {
        it("returns no-op restore on unsupported platform", () => {
            Object.defineProperty(process, "platform", { value: "freebsd" });
            const restore = recordFocus();
            expect(mockedExecFileSync).not.toHaveBeenCalled();
            restore();
            expect(mockedSpawn).not.toHaveBeenCalled();
        });
    });
});
